import { CancellationToken } from '../../../../base/common/cancellation.js';
import { ITextModel } from '../../../common/model.js';
import { FoldingRegions, MAX_LINE_NUMBER } from './foldingRanges.js';
import { FoldingLimitReporter, RangeProvider } from './folding.js';

const MAX_FOLDING_REGIONS_FOR_NAMED_DEFAULT = 5000;
const ID_NAMED_PROVIDER = 'named';

// Region name -> line range
export interface NamedRegion {
	name: string;
	startLineNumber: number;
	endLineNumber: number;
}

/**
 * Provider for named folding regions marked with #region <name> / #endregion comments
 */
export class NamedRangeProvider implements RangeProvider {
	readonly id = ID_NAMED_PROVIDER;
	private namedRegions: NamedRegion[] = [];

	constructor(
		private readonly editorModel: ITextModel,
		private readonly foldingRangesLimit: FoldingLimitReporter
	) { }

	dispose() { }

	compute(cancelationToken: CancellationToken): Promise<FoldingRegions | null> {
		return Promise.resolve(computeNamedRanges(this.editorModel, this.namedRegions, this.foldingRangesLimit));
	}

	/**
	 * Get all named regions in the document
	 */
	getNamedRegions(): NamedRegion[] {
		return this.namedRegions;
	}
}

const regionStartPattern = /#region\s+(.+?)$/;
const regionEndPattern = /#endregion/;

export function computeNamedRanges(
	model: ITextModel,
	namedRegions: NamedRegion[],
	foldingRangesLimit: FoldingLimitReporter = { limit: MAX_FOLDING_REGIONS_FOR_NAMED_DEFAULT, update: () => { } }
): FoldingRegions | null {
	const lineCount = model.getLineCount();
	const startIndexes: number[] = [];
	const endIndexes: number[] = [];
	const names: string[] = [];
	const regionStack: Array<{ name: string; startLineNumber: number }> = [];

	// Clear previous regions
	namedRegions.length = 0;

	for (let lineNumber = 1; lineNumber <= lineCount; lineNumber++) {
		const lineContent = model.getLineContent(lineNumber);
		const startMatch = lineContent.match(regionStartPattern);
		const endMatch = lineContent.match(regionEndPattern);

		if (startMatch) {
			// Found a region start marker
			const regionName = startMatch[1].trim();
			regionStack.push({
				name: regionName,
				startLineNumber: lineNumber
			});
		} else if (endMatch && regionStack.length > 0) {
			// Found a region end marker
			const region = regionStack.pop()!;

			// Only add if region has at least 2 lines (start and end)
			if (lineNumber > region.startLineNumber) {
				startIndexes.push(region.startLineNumber);
				endIndexes.push(lineNumber);
				names.push(region.name);

				// Store in namedRegions for quick access
				namedRegions.push({
					name: region.name,
					startLineNumber: region.startLineNumber,
					endLineNumber: lineNumber
				});

				// Check limit
				if (startIndexes.length >= foldingRangesLimit.limit) {
					foldingRangesLimit.update(lineCount, foldingRangesLimit.limit);
					break;
				}
			}
		}
	}

	if (startIndexes.length === 0) {
		return null;
	}

	foldingRangesLimit.update(startIndexes.length, false);

	// Convert to Uint32Array
	const startArray = new Uint32Array(startIndexes.length);
	const endArray = new Uint32Array(endIndexes.length);
	for (let i = 0; i < startIndexes.length; i++) {
		startArray[i] = startIndexes[i];
		endArray[i] = endIndexes[i];
	}

	return new FoldingRegions(startArray, endArray, names);
}

