209: 		if (!model || !this._isEnabled || model.isTooLargeForTokenization() || !this.hiddenRangeModel) {
210: 			return;
211: 		}
212: 		if (!state) {
213: 			return;
214: 		}
215: 
216: 		this._currentModelHasFoldedImports = !!state.foldedImports;
217: 		if (state.collapsedRegions && state.collapsedRegions.length > 0 && this.foldingModel) {
218: 			this._restoringViewState = true;
219: 			try {
220: 				this.foldingModel.applyMemento(state.collapsedRegions);
221: 			} finally {
222: 				this._restoringViewState = false;
223: 			}
224: 		}
225: 	}
226: 
227: 	private onModelChanged(): void {
228: 		this.localToDispose.clear();
229: 
230: 		const model = this.editor.getModel();
231: 		if (!this._isEnabled || !model || model.isTooLargeForTokenization()) {
232: 			// huge files get no view model, so they cannot support hidden areas
233: 			return;
234: 		}
235: 
236: 		this._currentModelHasFoldedImports = false;
237: 		this.foldingModel = new FoldingModel(model, this.foldingDecorationProvider);
238: 		this.localToDispose.add(this.foldingModel);
239: 
240: 		this.hiddenRangeModel = new HiddenRangeModel(this.foldingModel);
241: 		this.localToDispose.add(this.hiddenRangeModel);
242: 		this.localToDispose.add(this.hiddenRangeModel.onDidChange(hr => this.onHiddenRangesChanges(hr)));
243: 
244: 		this.updateScheduler = new Delayer<FoldingModel>(this.updateDebounceInfo.get(model));
245: 
246: 		this.cursorChangedScheduler = new RunOnceScheduler(() => this.revealCursor(), 200);
247: 		this.localToDispose.add(this.cursorChangedScheduler);
248: 		this.localToDispose.add(this.languageFeaturesService.foldingRangeProvider.onDidChange(() => this.onFoldingStrategyChanged()));
249: 		this.localToDispose.add(this.editor.onDidChangeModelLanguageConfiguration(() => this.onFoldingStrategyChanged())); // covers model language changes as well
250: 		this.localToDispose.add(this.editor.onDidChangeModelContent(e => this.onDidChangeModelContent(e)));
251: 		this.localToDispose.add(this.editor.onDidChangeCursorPosition(() => this.onCursorPositionChanged()));
252: 		this.localToDispose.add(this.editor.onMouseDown(e => this.onEditorMouseDown(e)));
253: 		this.localToDispose.add(this.editor.onMouseUp(e => this.onEditorMouseUp(e)));
254: 		this.localToDispose.add({
255: 			dispose: () => {
256: 				if (this.foldingRegionPromise) {
257: 					this.foldingRegionPromise.cancel();
258: 					this.foldingRegionPromise = null;
259: 				}
260: 				this.updateScheduler?.cancel();
261: 				this.updateScheduler = null;
262: 				this.foldingModel = null;
263: 				this.foldingModelPromise = null;
264: 				this.hiddenRangeModel = null;
265: 				this.cursorChangedScheduler = null;
266: 				this.rangeProvider?.dispose();
267: 				this.rangeProvider = null;
268: 			}
269: 		});
270: 		this.triggerFoldingModelChanged();
271: 	}
272: 
273: 	private onFoldingStrategyChanged() {
274: 		this.rangeProvider?.dispose();
275: 		this.rangeProvider = null;
276: 		this.triggerFoldingModelChanged();
277: 	}
278: 
279: 	private getRangeProvider(editorModel: ITextModel): RangeProvider {
280: 		if (this.rangeProvider) {
281: 			return this.rangeProvider;
282: 		}
283: 		const indentRangeProvider = new IndentRangeProvider(editorModel, this.languageConfigurationService, this._foldingLimitReporter);
284: 		this.rangeProvider = indentRangeProvider; // fallback
285: 		if (this._useFoldingProviders && this.foldingModel) {
286: 			const selectedProviders = FoldingController.getFoldingRangeProviders(this.languageFeaturesService, editorModel);
287: 			if (selectedProviders.length > 0) {
288: 				this.rangeProvider = new SyntaxRangeProvider(editorModel, selectedProviders, () => this.triggerFoldingModelChanged(), this._foldingLimitReporter, indentRangeProvider);
289: 			}
290: 		}
291: 		return this.rangeProvider;
292: 	}
293: 
294: 	public getFoldingModel(): Promise<FoldingModel | null> | null {
295: 		return this.foldingModelPromise;
296: 	}
297: 
298: 	private onDidChangeModelContent(e: IModelContentChangedEvent) {
299: 		this.hiddenRangeModel?.notifyChangeModelContent(e);
300: 		this.triggerFoldingModelChanged();
301: 	}
302: 
303: 
304: 	public triggerFoldingModelChanged() {
305: 		if (this.updateScheduler) {
306: 			if (this.foldingRegionPromise) {
307: 				this.foldingRegionPromise.cancel();
308: 				this.foldingRegionPromise = null;
309: 			}
310: 			this.foldingModelPromise = this.updateScheduler.trigger(() => {
311: 				const foldingModel = this.foldingModel;
312: 				if (!foldingModel) { // null if editor has been disposed, or folding turned off
313: 					return null;
314: 				}
315: 				const sw = new StopWatch();
316: 				const provider = this.getRangeProvider(foldingModel.textModel);
317: 				const foldingRegionPromise = this.foldingRegionPromise = createCancelablePromise(token => provider.compute(token));
318: 				return foldingRegionPromise.then(foldingRanges => {
319: 					if (foldingRanges && foldingRegionPromise === this.foldingRegionPromise) { // new request or cancelled in the meantime?
320: 						let scrollState: StableEditorScrollState | undefined;
321: 
322: 						if (this._foldingImportsByDefault && !this._currentModelHasFoldedImports) {
323: 							const hasChanges = foldingRanges.setCollapsedAllOfType(FoldingRangeKind.Imports.value, true);
324: 							if (hasChanges) {
325: 								scrollState = StableEditorScrollState.capture(this.editor);
326: 								this._currentModelHasFoldedImports = hasChanges;
327: 							}
328: 						}
329: 
330: 						// some cursors might have moved into hidden regions, make sure they are in expanded regions
331: 						const selections = this.editor.getSelections();
332: 						foldingModel.update(foldingRanges, toSelectedLines(selections));
333: 
334: 						scrollState?.restore(this.editor);
335: 
336: 						// update debounce info
337: 						const newValue = this.updateDebounceInfo.update(foldingModel.textModel, sw.elapsed());
338: 						if (this.updateScheduler) {
339: 							this.updateScheduler.defaultDelay = newValue;
340: 						}
341: 					}
342: 					return foldingModel;
343: 				});
344: 			}).then(undefined, (err) => {
345: 				onUnexpectedError(err);
346: 				return null;
347: 			});
348: 		}
349: 	}
