/*---------------------------------------------------------------------------------------------
 *  Copyright (c) Microsoft Corporation. All rights reserved.
 *  Licensed under the MIT License. See License.txt in the project root for license information.
 *--------------------------------------------------------------------------------------------*/

import assert from 'assert';
import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { computeNamedRanges } from '../../browser/namedRangeProvider.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';

interface ExpectedNamedRange {
	name: string;
	startLineNumber: number;
	endLineNumber: number;
}

function assertNamedRanges(lines: string[], expected: ExpectedNamedRange[]): void {
	const model = createTextModel(lines.join('\n'));
	const namedRegions: any[] = [];
	const actual = computeNamedRanges(model, namedRegions);

	if (expected.length === 0) {
		assert.strictEqual(actual, null);
	} else {
		assert.notStrictEqual(actual, null);
		assert.strictEqual(actual!.length, expected.length);

		for (let i = 0; i < expected.length; i++) {
			assert.strictEqual(actual!.getStartLineNumber(i), expected[i].startLineNumber, `Range ${i} start mismatch`);
			assert.strictEqual(actual!.getEndLineNumber(i), expected[i].endLineNumber, `Range ${i} end mismatch`);
			assert.strictEqual(actual!.getType(i), expected[i].name, `Range ${i} name mismatch`);
		}

		// Also verify namedRegions array
		assert.strictEqual(namedRegions.length, expected.length);
		for (let i = 0; i < expected.length; i++) {
			assert.strictEqual(namedRegions[i].name, expected[i].name);
			assert.strictEqual(namedRegions[i].startLineNumber, expected[i].startLineNumber);
			assert.strictEqual(namedRegions[i].endLineNumber, expected[i].endLineNumber);
		}
	}
	model.dispose();
}

suite('Named Range Folding', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	test('Single named region', () => {
		const lines = [
			'// #region MySection',
			'const x = 1;',
			'// #endregion'
		];
		assertNamedRanges(lines, [
			{ name: 'MySection', startLineNumber: 1, endLineNumber: 3 }
		]);
	});

	test('Multiple named regions', () => {
		const lines = [
			'// #region First',
			'code here',
			'// #endregion',
			'',
			'// #region Second',
			'more code',
			'// #endregion'
		];
		assertNamedRanges(lines, [
			{ name: 'First', startLineNumber: 1, endLineNumber: 3 },
			{ name: 'Second', startLineNumber: 5, endLineNumber: 7 }
		]);
	});

	test('Nested named regions', () => {
		const lines = [
			'// #region Outer',
			'  // #region Inner',
			'  code',
			'  // #endregion',
			'// #endregion'
		];
		assertNamedRanges(lines, [
			{ name: 'Outer', startLineNumber: 1, endLineNumber: 5 },
			{ name: 'Inner', startLineNumber: 2, endLineNumber: 4 }
		]);
	});

	test('Named region with spaces', () => {
		const lines = [
			'// #region   My Region With Spaces  ',
			'content',
			'// #endregion'
		];
		assertNamedRanges(lines, [
			{ name: 'My Region With Spaces', startLineNumber: 1, endLineNumber: 3 }
		]);
	});

	test('No regions', () => {
		const lines = [
			'const x = 1;',
			'const y = 2;'
		];
		assertNamedRanges(lines, []);
	});

	test('Unmatched endregion', () => {
		const lines = [
			'// #endregion',
			'// #region Section',
			'content',
			'// #endregion'
		];
		// Only the matched region should be included
		assertNamedRanges(lines, [
			{ name: 'Section', startLineNumber: 2, endLineNumber: 4 }
		]);
	});

	test('Block comment region markers', () => {
		const lines = [
			'/* #region MyBlock */',
			'code',
			'/* #endregion */'
		];
		assertNamedRanges(lines, [
			{ name: 'MyBlock', startLineNumber: 1, endLineNumber: 3 }
		]);
	});

	test('Regions with different comment styles', () => {
		const lines = [
			'# #region Python',
			'x = 1',
			'# #endregion'
		];
		assertNamedRanges(lines, [
			{ name: 'Python', startLineNumber: 1, endLineNumber: 3 }
		]);
	});
});

